`timescale 1ns / 1ps
 
module testbench_labtest_combinational;
 
    integer count;
    
    // ------------------ Specify variables generated by testbench ------------------ 
    reg in1, in2;
    
    // ------------------ Specify variables that are watched by testbench ------------------ 
    wire out1, out2, out3;
    
    labtest_q1_hardware myname(.a(in1),.b(in2),
                                .x(out1),.y(out2),.z(out3));
 
    // ------------------ Setup inputs ------------------
    // Provide initial values for inputs. The ‘initial’ command
    // is only valid within the testbench.
    // Can use this for all simple testbenches

	initial begin
		$dumpfile("testbench.vcd");
		$dumpvars(0, testbench_labtest_combinational);
		#200;
		$finish;
	end

    initial begin 
        count = 0;
    end
 
    always begin
        #50
        count=count+1;
    end
 
    // Toggle inputs at different rates to cover all input  
    always @(count) begin
        case (count)
            0       : begin in1<=1'b0; in2<=1'b0; end 
            1       : begin in1<=1'b0; in2<=1'b1; end 
            2       : begin in1<=1'b1; in2<=1'b0; end 
            default : begin in1<=1'b1; in2<=1'b1; end 
        endcase
    end
 
endmodule